/* exampleBench.c — micro-benchmark skeleton generated by the model.
   Compile with:  make benchFunc exampleBench
   Depends on:   tests/timings.h / tests/timings.c, -lm
*/
#include "exampleBench.h"
#include "timings.h"

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <time.h>
#include <stdint.h>

#define SAMPLES   30
#define ARRAY_LEN (1 << 20)  /* 1 M ints */

/* ---------- implementations ---------- */

uint64_t sumBaseline(const int *arr, int n) {
    uint64_t s = 0;
    for (int i = 0; i < n; i++) s += arr[i];
    return s;
}

uint64_t sumOptimized(const int *arr, int n) {
    uint64_t s0 = 0, s1 = 0, s2 = 0, s3 = 0;
    int i = 0;
    for (; i + 3 < n; i += 4) {
        s0 += arr[i];
        s1 += arr[i + 1];
        s2 += arr[i + 2];
        s3 += arr[i + 3];
    }
    for (; i < n; i++) s0 += arr[i];
    return s0 + s1 + s2 + s3;
}

/* ---------- main ---------- */

int main(void) {
    int *arr = malloc(ARRAY_LEN * sizeof(int));
    if (!arr) { fprintf(stderr, "OOM\n"); return 1; }
    for (int i = 0; i < ARRAY_LEN; i++) arr[i] = i & 0xFF;

    float timesBaseline[SAMPLES], timesOpt[SAMPLES];
    volatile uint64_t sink = 0;

    /* warm-up */
    for (int i = 0; i < 3; i++) sink += sumBaseline(arr, ARRAY_LEN);
    for (int i = 0; i < 3; i++) sink += sumOptimized(arr, ARRAY_LEN);

    /* time baseline */
    for (int s = 0; s < SAMPLES; s++) {
        struct timespec t0, t1;
        clock_gettime(CLOCK_MONOTONIC, &t0);
        sink += sumBaseline(arr, ARRAY_LEN);
        clock_gettime(CLOCK_MONOTONIC, &t1);
        timesBaseline[s] = (float)(t1.tv_sec - t0.tv_sec)
                         + (float)(t1.tv_nsec - t0.tv_nsec) * 1e-9f;
    }

    /* time optimized */
    for (int s = 0; s < SAMPLES; s++) {
        struct timespec t0, t1;
        clock_gettime(CLOCK_MONOTONIC, &t0);
        sink += sumOptimized(arr, ARRAY_LEN);
        clock_gettime(CLOCK_MONOTONIC, &t1);
        timesOpt[s] = (float)(t1.tv_sec - t0.tv_sec)
                    + (float)(t1.tv_nsec - t0.tv_nsec) * 1e-9f;
    }

    PerformanceMetrics mb = ComputePerformanceMetrics(timesBaseline, SAMPLES);
    PerformanceMetrics mo = ComputePerformanceMetrics(timesOpt,      SAMPLES);

    printf("=== exampleBench: array sum over %d ints, %d samples ===\n", ARRAY_LEN, SAMPLES);
    printf("Baseline  avg=%.3fms  median=%.3fms  p99=%.3fms\n",
           mb.averageTime * 1e3f, mb.medianTime * 1e3f, mb.p99Time * 1e3f);
    printf("Optimized avg=%.3fms  median=%.3fms  p99=%.3fms\n",
           mo.averageTime * 1e3f, mo.medianTime * 1e3f, mo.p99Time * 1e3f);

    if (mb.medianTime > 0)
        printf("Speedup: %.2fx\n", mb.medianTime / mo.medianTime);

    /* correctness check */
    uint64_t r1 = sumBaseline(arr, ARRAY_LEN);
    uint64_t r2 = sumOptimized(arr, ARRAY_LEN);
    if (r1 != r2) {
        printf("CORRECTNESS FAIL: baseline=%llu optimized=%llu\n",
               (unsigned long long)r1, (unsigned long long)r2);
        free(arr);
        return 1;
    }
    printf("Correctness: OK (both return %llu)\n", (unsigned long long)r1);
    (void)sink;
    free(arr);
    return 0;
}
